def validate_ocfl(root):
    import os
    import json
    import pyfs
    from pyfs import ocfl

    if isinstance(root, pyfs.PyFS):
        root = root.root

    if not os.path.exists(root):
        return False

    try:
        with open(os.path.join(root, 'manifest.json'), 'r') as f:
            manifest = json.load(f)
    except FileNotFoundError:
        return False

    if not ocfl.validate_manifest(manifest):
        return False

    for path in manifest['paths']:
        if not ocfl.validate_path(root, path):
            return False

    return True

