def absorption(args):
    result = []
    for i in range(len(args)):
        for j in range(i + 1, len(args)):
            if args[i] == args[j]:
                if args[j] == args[j] & (args[j] | args[i]):
                    result.append(args[i])
                elif args[j] == args[j] | (args[j] & args[i]):
                    result.append(args[i])
                elif args[j] == args[j] & (~args[j] | args[i]):
                    result.append(args[j] & args[i])
                elif args[j] == args[j] | (~args[j] & args[i]):
                    result.append(args[j] | args[i])
    return result

