def _validate_labels(labels: Dict) -> None:
    key_pattern = re.compile(r'^[a-zA-Z_][a-zA-Z0-9_]*$')
    value_pattern = re.compile(r'^[a-zA-Z0-9_\-\.]+$')

    errors = []
    for key, value in labels.items():
        if not isinstance(key, str):
            errors.append({str(key): 'expected string or bytes-like object'})
        elif not key_pattern.match(key):
            errors.append({str(key): f'Label key "{key}" does not match the regex {key_pattern.pattern}'})

        if not isinstance(value, str):
            errors.append({str(value): 'expected string or bytes-like object'})
        elif not value_pattern.match(value):
            errors.append({str(value): f'Label value "{value}" does not match the regex {value_pattern.pattern}'})
    if errors:
        raise ValidationError(errors)

