    if level == 0:
        return {}
    if level == -1:
        level = 999
    d = {}
    for k in d1:
        if k not in d2:
            d[k] = d1[k]
        elif isinstance(d1[k], dict) and isinstance(d2[k], dict):
            v = difference(d1[k], d2[k], level - 1)
            if v:
                d[k] = v
        elif d1[k] != d2[k]:
            d[k] = d1[k]
    return d

