import platform

def shlex_split(s, platform='this'):
    if platform == 'this':
        platform = 0 if platform.system().lower() == 'windows' else 1
    elif platform not in [0, 1]:
        raise ValueError("Invalid platform value")

    if platform == 0:
        # Windows/CMD
        return re.findall(r"[^\"\\]*(?:\\.[^\"\\]*)*|\"(?:\\.[^\"\\]*)*\"", s)
    else:
        # POSIX
        return re.findall(r"[^\\s\"]+|\"(?:\\.[^\"\\]*)*\"", s)

