def check_required_args(func):
    def wrapper(*args, **kwargs):
        required_args = func.__code__.co_varnames[:func.__code__.co_argcount]
        provided_args = [arg for arg in args if arg not in kwargs]
        if len(required_args) != len(provided_args):
            raise TypeError("Missing required arguments")
        for arg in required_args:
            if arg not in kwargs and arg not in provided_args:
                raise TypeError(f"Missing required argument: {arg}")
        return func(*args, **kwargs)
    return wrapper

