import re
from typing import Callable, Tuple, Set

def find_tags(text: str, replacer: Callable = None) -> Tuple[Set[str], str]:
    tags = set()
    replaced_text = text
    code_block = False
    lines = text.split('\n')
    for line in lines:
        if line.strip().startswith('<code>') or line.strip().startswith('<pre>'):
            code_block = True
        elif line.strip().startswith('</code>') or line.strip().startswith('</pre>'):
            code_block = False
        else:
            if not code_block:
                matches = re.findall(r'<(\w+)>', line)
                for match in matches:
                    tags.add(match)
                    if replacer:
                        replaced_text = replaced_text.replace(f'<{match}>', replacer(match))
    return tags, replaced_text

