import json
import xml.etree.ElementTree as ET
from urllib.parse import urlparse

def parse_webfinger(webfinger_url):
    url = urlparse(webfinger_url)
    if url.path.endswith('.json'):
        with open(url.path[1:]) as f:
            data = json.load(f)
    else:
        tree = ET.parse(url.path[1:])
        root = tree.getroot()
        data = {}
        for child in root:
            data[child.tag] = child.text

    if 'subject' in data:
        subject = data['subject']
    elif 'atom:link' in data and data['atom:link'][0].get('href'):
        subject = data['atom:link'][0].get('href')
    else:
        return None

    if subject.startswith('acct:'):
        username = subject[5:]
        domain = urlparse(subject).netloc
    else:
        return None

    return {'username': username, 'domain': domain}

